import { unstable_cache } from "next/cache";

export type Post = {
  id: string;
  title: string;
  body: string;
};

const posts: Post[] = [];

const readPosts = unstable_cache(
  async () => posts,
  ["posts"],
  { tags: ["posts"] }
);

export function getPosts() {
  return readPosts();
}

export async function createPost(input: { title: string; body: string }) {
  const post: Post = {
    id: crypto.randomUUID(),
    title: input.title,
    body: input.body
  };

  posts.unshift(post);
  return post;
}

